uniform vec2 u_resolution;
out vec4 fragColor;

void main() {
    vec2 uv = gl_FragCoord.xy / u_resolution;

    vec3 bottom = vec3(0.05, 0.05, 0.3);
    vec3 top    = vec3(1.0,  0.45, 0.1);

    vec3 color = mix(bottom, top, uv.y);

    fragColor = vec4(color, 1.0);
}

